M.s("alert-plain-inline-variations",'div()\n        .add(alert(success, "Success alert title")\n                .inline().plain()\n                .addDescription(\n                        "Success alert description. This should tell the user more information about the alert."))\n        .element()');M.s("alert-static-live-region",'div()\n        .add(alert(info, "Default live region configuration")\n                .closable()\n                .liveRegion()\n                .addDescription(alertDescription()\n                        .add(p()\n                                .add("This alert uses the recommended ")\n                                .add(Elements.code("liveRegion()"))\n                                .add(" modifier to automatically set ARIA attributes and CSS classes."))))\n        .add(br())\n        .add(alert(info, "Customized live region")\n                .closable()\n                .aria(live, "assertive")\n                .aria(atomic, true)\n                .aria(relevant, "additions text")\n                .addDescription(alertDescription()\n                        .add(p()\n                                .add("You can alternatively omit the ")\n                                .add(Elements.code("liveRegion()"))\n                                .add(" to specify ARIA attributes and CSS manually on the containing element."))))\n        .element()');
M.s("alert-group-static-inline",'div()\n        .add(alertGroup(staticInline)\n                .addAlert(alert(success, "Success alert").inline())\n                .addAlert(alert(info, "Info alert"))) // inline is added automatically!\n        .element()');M.s("alert-group-toast",'div()\n        .add(actionList()\n                .addItem(actionListItem()\n                        .add(button("Add toast success alert").secondary()\n                                .onClick((e, b) -> alertGroup(toast)\n                                        .addAlert(alert(success, "Toast success alert")))))\n                .addItem(actionListItem()\n                        .add(button("Add toast danger alert").secondary()\n                                .onClick((e, b) -> alertGroup(toast)\n                                        .addAlert(alert(danger, "Toast danger alert")))))\n                .addItem(actionListItem()\n                        .add(button("Add toast info alert").secondary()\n                                .onClick((e, b) -> alertGroup(toast)\n                                        .addAlert(alert(info, "Toast info alert"))))))\n        .element()');
M.s("alert-group-asynchronous",'final int[] counter = {0};\nfinal double[] intervalHandle = {0};\nreturn div()\n        .add(actionList()\n                .addItem(actionListItem()\n                        .add(button("Start async alerts").secondary()\n                                .onClick((e, b) -> intervalHandle[0] = setInterval(__ -> {\n                                    counter[0] = counter[0] + 1;\n                                    alertGroup(toast)\n                                            .addAlert(alert(danger, "Async notification " + counter[0]\n                                                    + " was added to the queue."));\n                                }, 1_000))))\n                .addItem(actionListItem()\n                        .add(button("Stop async alerts").secondary()\n                                .onClick((e, b) -> {\n                                    counter[0] = 0;\n                                    clearInterval(intervalHandle[0]);\n                                }))))\n        .element();');
M.s("slider-discrete",'HTMLContainerBuilder<HTMLElement>[] values = new HTMLContainerBuilder[]{span(), span(), span(), span(), span(),\n        span(), span()};\nreturn div()\n        .add(p().add("Slider value is ").add(values[0]))\n        .add(slider()\n                .value(50)\n                .customSteps(sliderSteps(\n                        sliderStep(0d),\n                        sliderStep(12.5, "1", true),\n                        sliderStep(25d, "2"),\n                        sliderStep(37.5, "3", true),\n                        sliderStep(50d, "4"),\n                        sliderStep(62.5, "5", true),\n                        sliderStep(75d, "6"),\n                        sliderStep(87.5, "7", true),\n                        sliderStep(100d, "8")))\n                .onChange((e, s, v) -> values[0].textContent(String.valueOf(v))))\n        .add(br())\n        .add(p().add("Slider value is ").add(values[1]))\n        .add(small().add("(min = 0, max = 200, step = 50)"))\n        .add(slider()\n                .value(50)\n                .range(0, 200, 50)\n                .showTicks()\n                .onChange((e, s, v) -> values[1].textContent(String.valueOf(v))))\n        .add(br())\n        .add(p().add("Slider value is ").add(values[2]))\n        .add(small().add("(min = -25, max = 75, step = 10, boundaries not shown)"))\n        .add(slider()\n                .value(25)\n                .range(-25, 75, 10)\n                .showTicks()\n                .showBoundaries(false)\n                .onChange((e, s, v) -> values[2].textContent(String.valueOf(v))))\n        .add(br())\n        .add(p().add("Slider value is ").add(values[3]))\n        .add(small().add("(min = -25, max = 75, step = 10, boundaries shown)"))\n        .add(slider()\n                .value(50)\n                .range(-25, 75, 10)\n                .showTicks()\n                .onChange((e, s, v) -> values[3].textContent(String.valueOf(v))))\n        .add(br())\n        .add(p().add("Slider value is ").add(values[4]))\n        .add(small().add("(min = -25, max = 75, step = 10, boundaries shown, ticks not shown)"))\n        .add(slider()\n                .value(50)\n                .range(-25, 75, 10)\n                .onChange((e, s, v) -> values[4].textContent(String.valueOf(v))))\n        .add(br())\n        .add(p().add("Slider value is ").add(values[5]))\n        .add(small().add("(max = 5, custom steps)"))\n        .add(slider()\n                .value(3)\n                .showTicks()\n                .customSteps(sliderSteps(\n                        sliderStep(0, "A"),\n                        sliderStep(1, "B"),\n                        sliderStep(2, "C"),\n                        sliderStep(3, "D"),\n                        sliderStep(4, "E"),\n                        sliderStep(5, "F")))\n                .onChange((e, s, v) -> values[5].textContent(String.valueOf(v))))\n        .add(br())\n        .add(p().add("Slider value is ").add(values[6]))\n        .add(small().add("(min = 12, max = 86, custom steps with non linear data)"))\n        .add(slider()\n                .value(25)\n                .showTicks()\n                .customSteps(sliderSteps(\n                        sliderStep(12),\n                        sliderStep(15),\n                        sliderStep(25),\n                        sliderStep(54),\n                        sliderStep(67),\n                        sliderStep(86)))\n                .onChange((e, s, v) -> values[6].textContent(String.valueOf(v))))\n        .add(br())\n        .element();');
M.s("slider-continuous",'HTMLContainerBuilder<HTMLElement>[] values = new HTMLContainerBuilder[]{span(), span()};\nreturn div()\n        .add(p().add("Slider value is ").add(values[0]))\n        .add(slider()\n                .value(50)\n                .onChange((e, s, v) -> values[0].textContent(String.valueOf(v))))\n        .add(br())\n        .add(p().add("Slider value is ").add(values[1]))\n        .add(small().add("(with tooltip over thumb)"))\n        .add(slider()\n                .value(50)\n                .toolTipOnThumb()\n                .customSteps(true, sliderSteps(\n                        sliderStep(0, "0%"),\n                        sliderStep(100, "100%")))\n                .onChange((e, s, v) -> values[1].textContent(String.valueOf(v))))\n        .element();');
M.s("slider-value-input",'div()\n        .add(slider()\n                .value(62.5)\n                .customSteps(sliderSteps(\n                        sliderStep(0d),\n                        sliderStep(12.5, "1", true),\n                        sliderStep(25d, "2"),\n                        sliderStep(37.5, "3", true),\n                        sliderStep(50d, "4"),\n                        sliderStep(62.5, "5", true),\n                        sliderStep(75d, "6"),\n                        sliderStep(87.5, "7", true),\n                        sliderStep(100d, "8")))\n                .addValueInput(textInput(number, Id.unique())))\n        .add(br())\n        .add(slider()\n                .value(50)\n                .customSteps(sliderSteps(\n                        sliderStep(0, "0%"),\n                        sliderStep(25, "25%", true),\n                        sliderStep(50, "50%"),\n                        sliderStep(75, "75%", true),\n                        sliderStep(100, "100%")))\n                .addValueInput(inputGroup()\n                        .addItem(inputGroupItem().fill()\n                                .addFormControl(textInput(number, Id.unique())))\n                        .addText(inputGroupText("%"))))\n        .add(br())\n        .add(slider()\n                .value(50)\n                .addValueInput(inputGroup()\n                        .addItem(inputGroupItem().fill()\n                                .addFormControl(textInput(number, Id.unique())))\n                        .addText(inputGroupText("%"))))\n        .element()');
M.s("slider-thumb-value-input",'div()\n        .add(slider()\n                .value(50)\n                .addValueInput(inputGroup()\n                        .addItem(inputGroupItem().fill()\n                                .addFormControl(textInput(number, Id.unique())))\n                        .addText(inputGroupText("%")), aboveThumb))\n        .element()');M.s("slider-actions",'Slider slider0 = slider();\nSlider slider1 = slider();\nHTMLContainerBuilder<HTMLElement> value = span();\n\nreturn div()\n        .add(p().add("Slider value is ").add(value))\n        .add(slider0\n                .value(50)\n                .addStartActions(sliderActions()\n                        .addAction(button().plain().icon(minus())\n                                .on(click, e -> slider0.decrease())))\n                .addEndActions(sliderActions()\n                        .addAction(button().plain().icon(plus())\n                                .on(click, e -> slider0.increase())))\n                .onChange((e, s, v) -> value.textContent(String.valueOf(v))))\n        .add(br())\n        .add(slider1\n                .value(50)\n                .addValueInput(inputGroup()\n                        .addItem(inputGroupItem().fill()\n                                .addFormControl(textInput(number, Id.unique())))\n                        .addText(inputGroupText("%")))\n                .addEndActions(sliderActions()\n                        .addAction(button().plain().icon(lockOpen()).style("width", "16px")\n                                .onClick((event, button) -> {\n                                    slider1.disabled(!slider1.isDisabled());\n                                    if (slider1.isDisabled()) {\n                                        button.icon(lock());\n                                    } else {\n                                        button.icon(lockOpen());\n                                    }\n                                }), false)))\n        .element();');
M.s("slider-disabled",'Slider slider = slider();\nHTMLContainerBuilder<HTMLElement> value = span();\nsetTimeout(__ -> slider.value(50), 333);\nreturn div()\n        .add(p().add("Slider value is ").add(value))\n        .add(slider\n                .disabled()\n                .customSteps(sliderSteps(\n                        sliderStep(0d),\n                        sliderStep(12.5, "1", true),\n                        sliderStep(25d, "2"),\n                        sliderStep(37.5, "3", true),\n                        sliderStep(50d, "4"),\n                        sliderStep(62.5, "5", true),\n                        sliderStep(75d, "6"),\n                        sliderStep(87.5, "7", true),\n                        sliderStep(100d, "8")))\n                .onChange((e, s, v) -> value.textContent(s.currentStep().label)))\n        .element();');
M.s("tig-basic",'div()\n        .add(textInputGroup()\n                .addMain(textInputGroupMain("basic-text-input-group-0")))\n        .element()');M.s("tig-disabled",'div()\n        .add(textInputGroup()\n                .addMain(textInputGroupMain("disabled-text-input-group-0")\n                        .value("Disabled"))\n                .disabled())\n        .element()');M.s("tig-utilities-and-icon",'TextInputGroup textInputGroup = textInputGroup();\ntextInputGroup\n        .addMain(textInputGroupMain("tig-utilities-and-icon-0")\n                .icon(search())\n                .placeholder("Placeholder")\n                .onChange((e, tig, value) -> setVisible(tig.utilities(), !value.isEmpty())))\n        .addUtilities(textInputGroupUtilities()\n                .add(button().icon(times()).plain()\n                        .on(click, e -> textInputGroup.main().value("", true))));\nreturn div()\n        .add(textInputGroup)\n        .element();');
M.s("tig-filters",'ObservableValue<Boolean> chipsPresent = ov(true);\nObservableValue<Boolean> textEntered = ov(false);\n\nTextInputGroup textInputGroup = textInputGroup();\nChipGroup chipGroup = chipGroup();\nCloseHandler<Chip> closeHandler = (event, chip) -> chipsPresent.set(!chipGroup.values().isEmpty());\nchipGroup.addChips(asList("one", "two", "three", "four", "five", "six", "seven", "eight", "nine", "ten",\n        "eleven", "twelve"), text -> chip(text).onClose(closeHandler));\n\ntextInputGroup\n        .addMain(textInputGroupMain("tig-filters-0")\n                .addChipGroup(chipGroup)\n                .placeholder("Placeholder")\n                .onChange((e, tig, value) -> {\n                    textEntered.set(!value.isEmpty());\n                    if (Key.Enter.match(e) && !value.isEmpty()) {\n                        chipGroup.addChip(chip(value).onClose(closeHandler));\n                        tig.main().value("");\n                        chipsPresent.set(true);\n                        textEntered.set(false);\n                    }\n                }))\n        .addUtilities(textInputGroupUtilities(false)\n                .add(button().icon(times()).plain()\n                        .on(click, e -> {\n                            chipGroup.clear();\n                            textInputGroup.main().value("");\n                            chipsPresent.set(false);\n                            textEntered.change(false);\n                        })));\n\nchipsPresent.subscribe((current, previous) -> {\n    setVisible(chipGroup, current);\n    if (current) {\n        textInputGroup.main().removeIcon();\n    } else {\n        textInputGroup.main().icon(search());\n        setVisible(textInputGroup.utilities(), textEntered.get());\n    }\n});\ntextEntered.subscribe((current, previous) -> {\n    if (current) {\n        setVisible(textInputGroup.utilities(), true);\n    } else {\n        setVisible(textInputGroup.utilities(), chipsPresent.get());\n    }\n});\n\nreturn div()\n        .add(textInputGroup)\n        .element();');
M.s("text-area-basic",'div()\n        .add(textArea("basic-text-area-0"))\n        .element()');M.s("text-area-invalid",'div()\n        .add(textArea("invalid-text-area-0").validated(error))\n        .element()');M.s("text-area-validated",'final double[] handle = {0};\nHelperText helperText = helperText("Share your thoughts.");\nTextArea textArea = textArea("validated-text-area-0")\n        .onChange((e, ta, value) -> {\n            clearTimeout(handle[0]);\n            ta.validated(default_);\n            helperText.firstItem()\n                    .status(default_)\n                    .text("Validating...");\n            handle[0] = setTimeout(__ -> {\n                if (value.isEmpty()) {\n                    ta.validated(warning);\n                    helperText.firstItem()\n                            .status(warning)\n                            .text("You must have something to say");\n                } else {\n                    if (value.length() < 10) {\n                        ta.validated(error);\n                        helperText.firstItem()\n                                .status(error)\n                                .text("You\'re being too brief, please enter at least 10 characters.");\n                    } else {\n                        ta.validated(success);\n                        helperText.firstItem()\n                                .status(success)\n                                .text("Thanks for your comments!");\n                    }\n                }\n            }, 1234);\n        });\nreturn div()\n        .add(form()\n                .add(formGroup()\n                        .addLabel(formGroupLabel("Comments:"))\n                        .addControl(formGroupControl()\n                                .addControl(textArea)\n                                .addHelperText(helperText))))\n        .element();');
M.s("text-area-vertical",'div()\n        .add(textArea("vertical-text-area-0").resize(vertical))\n        .element()');M.s("text-area-horizontal",'div()\n        .add(textArea("horizontal-text-area-0").resize(horizontal))\n        .element()');M.s("text-area-both",'div()\n        .add(textArea("horizontal-text-area-0").resize(both))\n        .element()');M.s("text-area-disabled",'div()\n        .add(textArea("disabled-text-area-0").disabled())\n        .element()');M.s("text-area-readonly",'Checkbox plainToggle = checkbox("plain-toggle", "plain-toggle", "Plain read only variant");\nTextArea readOnlyTextArea = textArea("readonly-text-area-0", "read only text area example")\n        .readonly();\nreturn div()\n        .add(div().css(util("mb-sm"))\n                .add(plainToggle.onChange((e, c, value) -> readOnlyTextArea.plain(value))))\n        .add(readOnlyTextArea)\n        .element();');
M.s("text-auto-size",'div()\n        .add(textArea("auto-size-text-area-0").autoResize())\n        .element()');M.s("tooltip-basic",'div().style("margin", "100px")\n        .add(button("I have a tooltip").primary()\n                .id("tooltip-basic-button"))\n        .add(tooltip(By.id("tooltip-basic-button"), LoremIpsum.words()))\n        .element()');M.s("tooltip-dynamic",'Tooltip tooltip = tooltip(By.id("tooltip-dynamic-button"), "Copy to clipboard")\n        .onClose((e, t) -> t.text("Copy to clipboard"))\n        .appendToBody();\nreturn div().style("margin", "100px")\n        .add(button().icon(copy()).plain()\n                .aria(label, "Copy")\n                .id("tooltip-dynamic-button")\n                .onClick((e, b) -> tooltip.text("Successfully copied to clipboard!")))\n        .element();');
M.s("tooltip-auto",'Button button = button("Tooltip");\nonAttach(button, mr -> {\n    ScrollIntoViewOptions options = ScrollIntoViewOptions.create();\n    options.setBlock("center");\n    options.setInline("center");\n    button.element().scrollIntoView(options);\n});\nreturn div().style("width", "720px")\n        .add(div().css("pfj-tooltip-box")\n                .add(button.css("pfj-tooltip-button").primary()\n                        .id("tooltip-options-button"))\n                .add(tooltip(By.id("tooltip-options-button"), LoremIpsum.words())\n                        .placement(auto)))\n        .element();');
